section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/design-tokens-basics.json",
  "title": "Design Tokens Basics",
  "type": "object",
  "required": [
    "artefact_id",
    "tokens_file_path",
    "categories",
    "naming_convention",
    "themes",
    "consumer_outputs",
    "owner",
    "last_touched",
    "template_version",
    "status"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "tokens_file_path": {
      "type": "string",
      "minLength": 1
    },
    "categories": {
      "type": "array",
      "minItems": 6,
      "description": "the six canonical categories present"
    },
    "naming_convention": {
      "type": "string",
      "description": "category.subcategory.scale | category-subcategory-scale"
    },
    "themes": {
      "type": "array",
      "minItems": 1,
      "description": "theme variant names"
    },
    "consumer_outputs": {
      "type": "array",
      "minItems": 1,
      "description": "generated outputs (e.g. css-variables.css, tokens.swift)"
    }
  },
  "additionalProperties": false
}
